              <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"1fr 1fr",gap:12}}>{[{s:"overdue",title:"Quá hạn",border:"#fca5a5",hdr:"#fef2f2"},{s:"nearly_due",title:"Sắp hết hạn",border:"#fde68a",hdr:"#fefce8"}].map(({s,title,border,hdr})=>{const list=computed.filter(t=>t.status===s);return(<div key={s} style={{background:"#fff",borderRadius:10,border:"1px solid "+border,overflow:"hidden"}}><div style={{background:hdr,padding:"8px 12px",display:"flex",alignItems:"center",gap:8}}><span style={{width:8,height:8,borderRadius:"50%",background:STATUS[s].dot}}/><span style={{fontWeight:600,fontSize:13,color:STATUS[s].col}}>{title} ({list.length})</span></div><div style={{maxHeight:150,overflowY:"auto"}}>{list.length===0?<div style={{padding:14,textAlign:"center",color:"#9ca3af",fontSize:13}}>Không có</div>:list.map(t=>(<div key={t.id} onClick={()=>{setModal(t);loadComments(t.id);}} style={{padding:"8px 12px",borderBottom:"1px solid #f3f4f6",cursor:"pointer"}}><div style={{fontSize:13,fontWeight:500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.title}</div><div style={{fontSize:11,color:"#6b7280",marginTop:1}}>{t.dept} · {getEmp(t.eid)?.name||"–"} · {t.deadline}</div></div>))}</div></div>);})}</div>
